package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithRecordSeparator() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        char recordSeparator = '\n';
        CSVFormat csvFormat = new CSVFormat(COMMA, DOUBLE_QUOTE_CHAR, null, null, null, false, true, CRLF,
                null, null, null, false, false, false, false, false);

        // When
        Method method = CSVFormat.class.getDeclaredMethod("withRecordSeparator", char.class);
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(csvFormat, recordSeparator);

        // Then
        assertEquals(String.valueOf(recordSeparator), result.getRecordSeparator());
    }
}
